LETS MAKE AN PWA APP WHICH DISPLAYS THE STOCK WITH HELP OF APPSCRIPT 

BELOW IS MY APPSCRIPT CODE
// --- IMPORTANT SETUP ---
// To run this script, you MUST enable these Advanced Google Services:
// 1. In the Apps Script editor, click on "Services" (+ icon) in the left sidebar.
// 2. Find and add: "Drive API", "Gmail API"
// 3. These services will be available as Drive, Gmail objects in the script.

// --- CONFIGURATION ---
const FOLDER_ID = '1sUqAqiYvB3k_zay4eI1Qm5zxTqVaznWl';
const FILENAME_REGEX = /^modenik_inventory_report_(\d{8}_\d{6})/;
const EMAIL_RECIPIENT = 'hemantpb123@gmail.com';
const PDF_SUBFOLDER_NAME = 'Stock_PDFs';
// PASTE YOUR DEPLOYMENT LINK HERE
const WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbx2uuPBKiJZpnjuew7vdeRm9Q9oxqX5DQXE1LEdKSYClcPoW8EKUbvz_PXc1PJJR1edGw/exec';

// Global variable to store current stock data
let globalStockData = [];

// --- HELPER FUNCTIONS ---

/**
 * Finds the latest stock report file in the specified Google Drive folder.
 */
function getLatestStockFile() {
  const folder = DriveApp.getFolderById(FOLDER_ID);
  const files = folder.getFiles();
  let latestFile = null;
  let latestTimestamp = '';

  while (files.hasNext()) {
    const file = files.next();
    const fileName = file.getName();
    const match = fileName.match(FILENAME_REGEX);

    if (match) {
      const timestamp = match[1];
      if (timestamp > latestTimestamp) {
        latestTimestamp = timestamp;
        latestFile = file;
      }
    }
  }

  if (latestFile) {
    return { file: latestFile, timestamp: latestTimestamp };
  }
  return null;
}

/**
 * Gets or creates the PDF subfolder
 */
function getOrCreatePDFFolder() {
  const parentFolder = DriveApp.getFolderById(FOLDER_ID);
  const folders = parentFolder.getFoldersByName(PDF_SUBFOLDER_NAME);

  if (folders.hasNext()) {
    return folders.next();
  } else {
    return parentFolder.createFolder(PDF_SUBFOLDER_NAME);
  }
}

/**
 * Deletes old PDF files from the PDF folder
 */
function deleteOldPDFs(pdfFolder) {
  const files = pdfFolder.getFiles();
  let deletedCount = 0;

  while (files.hasNext()) {
    const file = files.next();
    if (file.getName().endsWith('.pdf')) {
      file.setTrashed(true);
      deletedCount++;
    }
  }

  Logger.log(`Deleted ${deletedCount} old PDF files`);
}

/**
 * Parses stock data from column B (category), Q (item details), and AB (quantity).
 */
function parseStockSheet(file) {
  let tempSheetId = null;
  try {
    let tempGoogleSheet = null;
    const maxRetries = 3;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        Logger.log(`Attempting to convert file (attempt ${attempt}/${maxRetries})...`);

        const resource = {
          title: `[TEMP] ${file.getName()}`,
          mimeType: MimeType.GOOGLE_SHEETS
        };
        tempGoogleSheet = Drive.Files.create(resource, file.getBlob());
        tempSheetId = tempGoogleSheet.id;
        Logger.log(`Successfully created temp sheet: ${tempSheetId}`);
        break;

      } catch (apiError) {
        Logger.log(`Attempt ${attempt} failed: ${apiError.toString()}`);

        if (attempt === maxRetries) {
          throw apiError;
        }

        const waitTime = Math.pow(2, attempt) * 1000;
        Logger.log(`Waiting ${waitTime}ms before retry...`);
        Utilities.sleep(waitTime);
      }
    }

    if (!tempSheetId) {
      throw new Error('Failed to create temporary sheet after retries');
    }

    const spreadsheet = SpreadsheetApp.openById(tempSheetId);
    const sheet = spreadsheet.getSheets()[0];
    const lastRow = sheet.getLastRow();

    if (lastRow < 4) return [];

    const dataRange = sheet.getRange(4, 1, lastRow - 3, sheet.getLastColumn());
    const values = dataRange.getValues();

    const COL_B_INDEX = 1;
    const COL_Q_INDEX = 16;
    const COL_AB_INDEX = 27;

    const stockData = [];

    for (let i = 0; i < values.length; i++) {
      const row = values[i];
      const category = row[COL_B_INDEX];
      const qData = row[COL_Q_INDEX];

      if (!qData || qData === '') {
        break;
      }

      const qty = parseInt(row[COL_AB_INDEX], 10) || 0;
      const parts = qData.toString().split(',').map(p => p.trim());

      if (parts.length >= 3 && category) {
        const itemName = parts[0].split('-')[0].trim();
        const color = parts[1];
        const size = parts[2];

        if (itemName && color && size) {
          stockData.push({
            category: category.toString().trim(),
            itemName: itemName,
            color: color,
            size: size,
            qty: qty
          });

          Logger.log(`Row ${i}: Category=${category}, Item=${itemName}, Color=${color}, Size=${size}, Qty=${qty}`);
        }
      }
    }

    Logger.log(`Total items parsed: ${stockData.length}`);
    return stockData;

  } finally {
    if (tempSheetId) {
      try {
        Logger.log(`Cleaning up temp sheet: ${tempSheetId}`);
        Drive.Files.remove(tempSheetId);
        Logger.log('Temp sheet deleted successfully');
      } catch (cleanupError) {
        Logger.log(`Warning: Failed to cleanup temp sheet: ${cleanupError.toString()}`);
      }
    }
  }
}

/**
 * Groups stock data by category, then by item name.
 */
function groupStockByCategory(stockData) {
  const categorized = {};

  for (const item of stockData) {
    if (!categorized[item.category]) {
      categorized[item.category] = {};
    }

    if (!categorized[item.category][item.itemName]) {
      categorized[item.category][item.itemName] = [];
    }

    categorized[item.category][item.itemName].push({
      color: item.color,
      size: item.size,
      qty: item.qty
    });
  }

  return categorized;
}

/**
 * Creates a PDF from the latest stock data
 */
function createCategoryPDF(categoryName, itemsData, timestamp, pdfFolder) {
  try {
    Utilities.sleep(1000);

    const doc = DocumentApp.create(`${categoryName}_Stock_Report_${timestamp}`);
    const docId = doc.getId();
    const body = doc.getBody();

    Logger.log(`Created document for ${categoryName}: ${docId}`);

    const itemNames = Object.keys(itemsData).sort();
    const namedRanges = {};

    const title = body.appendParagraph(`${categoryName.toUpperCase()} - STOCK REPORT`);
    title.setFontSize(18).setBold(true);
    title.setAlignment(DocumentApp.HorizontalAlignment.CENTER);

    const subtitle = body.appendParagraph(`Generated: ${new Date().toLocaleString()}`);
    subtitle.setAlignment(DocumentApp.HorizontalAlignment.CENTER);
    subtitle.setFontSize(10);

    body.appendParagraph('');
    body.appendParagraph('INDEX:').setFontSize(14).setBold(true);
    body.appendParagraph('');

    const indexTable = body.appendTable();
    indexTable.setBorderColor('#999999');

    const indexHeader = indexTable.appendTableRow();
    const headerCell = indexHeader.appendTableCell('Item Name');
    headerCell.setBackgroundColor('#2196F3');
    headerCell.getChild(0).asParagraph().setForegroundColor('#FFFFFF').setBold(true);

    body.appendPageBreak();

    const MAX_ROWS_PER_PAGE = 35;
    let currentPageRows = 0;

    for (let i = 0; i < itemNames.length; i++) {
      const itemName = itemNames[i];
      const variants = itemsData[itemName];

      const colorGroups = {};
      let totalQty = 0;

      for (const variant of variants) {
        if (!colorGroups[variant.color]) {
          colorGroups[variant.color] = [];
        }
        colorGroups[variant.color].push(variant);
        totalQty += variant.qty;
      }

      const numColorRows = Object.keys(colorGroups).length;
      const itemRows = 1 + 1 + 1 + numColorRows + 1 + 2;

      if (currentPageRows > 0 && (currentPageRows + itemRows) > MAX_ROWS_PER_PAGE) {
        body.appendPageBreak();
        currentPageRows = 0;
      }

      const itemHead = body.appendParagraph(itemName);
      itemHead.setFontSize(14).setBold(true);
      itemHead.setBackgroundColor('#2196F3');
      itemHead.setForegroundColor('#FFFFFF');

      const rangeBuilder = doc.newRange();
      rangeBuilder.addElement(itemHead);
      const range = rangeBuilder.build();
      const namedRangeName = 'item_' + itemName.replace(/[^a-zA-Z0-9]/g, '_');
      doc.addNamedRange(namedRangeName, range);
      namedRanges[itemName] = namedRangeName;

      body.appendParagraph('');

      const compactTable = body.appendTable();
      compactTable.setBorderColor('#999999');

      const hRow = compactTable.appendTableRow();
      const hCell1 = hRow.appendTableCell('Color');
      hCell1.setBackgroundColor('#E3F2FD');
      hCell1.getChild(0).asParagraph().setBold(true);

      const hCell2 = hRow.appendTableCell('Size Details');
      hCell2.setBackgroundColor('#E3F2FD');
      hCell2.getChild(0).asParagraph().setBold(true);

      for (const color of Object.keys(colorGroups).sort()) {
        const colorVariants = colorGroups[color];
        const sizeDetails = colorVariants
          .map(v => `${v.size}: ${v.qty}`)
          .join(' | ');

        const dRow = compactTable.appendTableRow();
        dRow.appendTableCell(color);
        dRow.appendTableCell(sizeDetails);
      }

      const tRow = compactTable.appendTableRow();
      const tCell1 = tRow.appendTableCell('TOTAL');
      tCell1.setBackgroundColor('#FFF9C4');
      tCell1.getChild(0).asParagraph().setBold(true);

      const tCell2 = tRow.appendTableCell(totalQty.toString());
      tCell2.setBackgroundColor('#FFF9C4');
      tCell2.getChild(0).asParagraph().setBold(true);

      body.appendParagraph('');
      body.appendParagraph('');

      currentPageRows += itemRows;
    }

    for (const itemName of itemNames) {
      const indexRow = indexTable.appendTableRow();
      const cell = indexRow.appendTableCell(itemName);
      const para = cell.getChild(0).asParagraph();
      para.setBold(true).setForegroundColor('#0066CC');

      if (namedRanges[itemName]) {
        para.setLinkUrl('#heading=' + namedRanges[itemName]);
      }
    }

    doc.saveAndClose();
    Utilities.sleep(1000);

    const pdfBlob = DriveApp.getFileById(docId).getAs('application/pdf');
    const pdfFileName = `${categoryName}_Stock_Report_${timestamp}.pdf`;

    Logger.log(`Converting to PDF: ${pdfFileName}`);

    const pdfFile = pdfFolder.createFile(pdfBlob);
    pdfFile.setName(pdfFileName);

    Logger.log(`PDF created: ${pdfFileName}`);

    DriveApp.getFileById(docId).setTrashed(true);

    return {
      id: pdfFile.getId(),
      name: pdfFileName,
      url: pdfFile.getUrl(),
      category: categoryName
    };
  } catch (error) {
    Logger.log(`Error creating PDF for ${categoryName}: ${error.toString()}`);
    Logger.log(`Stack: ${error.stack}`);
    throw error;
  }
}

