/**
 * Main function to orchestrate the entire process.
 */
function generateAndEmailStockReport() {
  try {
    const latest = getLatestStockFile();

    if (!latest) {
      Logger.log('No valid stock report file found.');
      return;
    }

    Logger.log(`Processing file: ${latest.file.getName()}`);

    const stockItems = parseStockSheet(latest.file);

    if (stockItems.length === 0) {
      Logger.log('No stock data found in the file.');
      return;
    }

    globalStockData = stockItems;

    const categorizedData = groupStockByCategory(stockItems);
    const categories = Object.keys(categorizedData);
    Logger.log(`Found ${categories.length} categories: ${categories.join(', ')}`);

    const pdfFolder = getOrCreatePDFFolder();
    Logger.log(`PDF Folder ID: ${pdfFolder.getId()}`);

    deleteOldPDFs(pdfFolder);

    const pdfFiles = [];
    for (const category of categories) {
      Logger.log(`Creating PDF for category: ${category}`);
      const pdfInfo = createCategoryPDF(category, categorizedData[category], latest.timestamp, pdfFolder);
      pdfFiles.push(pdfInfo);
    }

    Logger.log(`Created ${pdfFiles.length} PDFs`);

    sendStockReportEmail(WEB_APP_URL, latest.timestamp);

    Logger.log(`Email sent to ${EMAIL_RECIPIENT}`);

  } catch (error) {
    Logger.log('Error: ' + error.toString() + "\n" + error.stack);
  }
}

/**
 * Web app entry point - serves interactive HTML with full mobile optimization
 */
function doGet(e) {
  try {
    const userAgent = e.userAgent || 'unknown';
    Logger.log('User Agent: ' + userAgent);

    const latest = getLatestStockFile();

