        .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);
    }

    const stockItems = parseStockSheet(latest.file);
    const categorizedData = groupStockByCategory(stockItems);

    const html = `
      <!DOCTYPE html>
