              flex: 1 1 100%;
            }

            .items-grid {
              grid-template-columns: 1fr;
            }

            .header {
              padding: 12px;
            }

            .content {
              padding: 10px;
            }
          }
        </style>
      </head>
      <body>
        <div class="container">
          <div class="header">
            <h1>📦 Stock Management</h1>
            <p>Generated ${new Date().toLocaleString()}</p>
          </div>

          <div class="controls">
            <div class="search-box">
              <input type="text" id="searchInput" placeholder="🔍 Search item, color, size...">
            </div>
            <div class="filter-category">
              <button class="category-btn active" data-category="all">All</button>
              ${Object.keys(categorizedData).slice(0, 10).map(cat => `<button class="category-btn" data-category="${cat}">${cat.substring(0, 10)}</button>`).join('')}
            </div>
          </div>

          <div class="content">
            ${Object.keys(categorizedData).map(category => `
              <div class="category-section visible" data-category="${category}">
                <div class="category-title">${category}</div>
